/// <summary>
///    Checks that the value in the <c>AccountRelation</c> field is valid.
/// </summary>
/// <returns>
///    true if the value is valid; otherwise, false.
/// </returns>
boolean checkAccountRelation()
{
    if (!this.AccountRelation)
    {
        return true;
    }

    if (!CustTable::exist(this.AccountRelation))
    {
        return false;
    }

    return true;
}

