/// <summary>
///    Overrides of standard delete method and ensures that lines and results are deleted too.
/// </summary>
public void delete()
{
    KPMGCommon_InventTestCertOfAnalysisLine_PackingSlip        inventTestCertOfAnalysisLine_PackingSlip;

    ttsbegin;

    delete_from inventTestCertOfAnalysisLine_PackingSlip
        where inventTestCertOfAnalysisLine_PackingSlip.InventCertificateOfAnalysisId        == this.InventCertificateOfAnalysisId;

    super();

    ttscommit;
}

/// <summary>
