/// <summary>
///    Determines whether the specified record in the <c>KPMGCommon_InventTestCertOfAnalysisTable_PackingSlip</c> table exists.
/// </summary>
/// <param name="_inventCertificateOfAnalysisId">
///    The certificate of analysis ID of the record to find.
/// </param>
/// <returns>
///    true if the specified record exists; otherwise, false.
/// </returns>
static boolean exist(InventCertificateOfAnalysisId _inventCertificateOfAnalysisId)
{
    return _inventCertificateOfAnalysisId &&
        (select  firstonly   KPMGCommon_InventTestCertOfAnalysisTable_PackingSlip
         where  KPMGCommon_InventTestCertOfAnalysisTable_PackingSlip.InventCertificateOfAnalysisId == _inventCertificateOfAnalysisId).RecId != 0;
}

/// <summary>
///    Finds the specified record in the <c>KPMGCommon_InventTestCertOfAnalysisTable_PackingSlip</c> table.
/// </summary>
/// <param name="_inventCertificateOfAnalysisId">
///    The certificate of analysis ID of the record to find.
/// </param>
/// <param name="_forUpdate">
///    A Boolean value that indicates whether to read the record for update; optional.
/// </param>
/// <returns>
///    A record in the <c>InventTestArea</c> table; otherwise, an empty record.
/// </returns>
static KPMGCommon_InventTestCertOfAnalysisTable_PackingSlip find(
    InventCertificateOfAnalysisId   _inventCertificateOfAnalysisId,
    boolean                         _forUpdate = false)
{
    KPMGCommon_InventTestCertOfAnalysisTable_PackingSlip   inventTestCertOfAnalysisTable_PackingSlip;

    inventTestCertOfAnalysisTable_PackingSlip.selectForUpdate(_forUpdate);

    if (_inventCertificateOfAnalysisId)
    {
        select firstonly    inventTestCertOfAnalysisTable_PackingSlip
        where   inventTestCertOfAnalysisTable_PackingSlip.InventCertificateOfAnalysisId == _inventCertificateOfAnalysisId;
    }

    return inventTestCertOfAnalysisTable_PackingSlip;
}

public static NumberSeq numberSeqInventCertificateOfAnalysisId(boolean makeDecisionLater = true)
{
    return NumberSeq::newGetNum(InventParameters::numRefCertificateOfAnalysisId(),makeDecisionLater);
}

InventCertificateOfAnalysisId initInventCertificateOfAnalysisId(boolean makeDecisionLater = true)
{
    NumberSeq numberSeqInventCertificateOfAnalysisId = KPMGCommon_InventTestCertOfAnalysisTable_PackingSlip::numberSeqInventCertificateOfAnalysisId(makeDecisionLater);

    InventCertificateOfAnalysisId inventCertificateOfAnalysisId = numberSeqInventCertificateOfAnalysisId.num();

    return inventCertificateOfAnalysisId;
}
